#!/usr/bin/env python3
import json
import re
import time
from typing import Dict

def extract_term_name(content: str) -> str:
    """从简介中提取术语名称"""
    # 尝试提取第一个逗号前的内容
    if '，' in content:
        name_part = content.split('，')[0]
        # 如果名称部分太长，可能是完整句子，尝试提取关键名词
        if len(name_part) > 20:
            # 尝试匹配中文名称模式
            match = re.search(r'([\u4e00-\u9fa5]{2,10}学派|[\u4e00-\u9fa5]{2,10}理论|[\u4e00-\u9fa5]{2,10}学)', name_part)
            if match:
                return match.group(1)
            else:
                return name_part[:15]
        return name_part
    return content[:20]

def parse_term_fields(content: str) -> Dict[str, str]:
    """解析术语字段"""
    fields = {}
    
    # 定义字段模式
    patterns = {
        '简介': r'\*\*简介\*\*[：:](.*?)(?=\n\*\*|\Z)',
        '英文名': r'\*\*英文名\*\*[：:](.*?)(?=\n\*\*|\Z)',
        '学术领域': r'\*\*学术领域\*\*[：:](.*?)(?=\n\*\*|\Z)',
        '学术贡献': r'\*\*学术贡献\*\*[：:](.*?)(?=\n\*\*|\Z)',
        '学术影响': r'\*\*学术影响\*\*[：:](.*?)(?=\n\*\*|\Z)'
    }
    
    for field, pattern in patterns.items():
        match = re.search(pattern, content, re.DOTALL)
        fields[field] = match.group(1).strip() if match else ""
    
    return fields

